from __future__ import annotations

import json

from report_app.markdown import render_inventory_markdown


def render_json(title: str, sections: list[dict[str, object]]) -> str:
    return json.dumps({"title": title, "sections": sections}, sort_keys=True)


def render_markdown(
    title: str,
    sections: list[dict[str, object]],
    owner_summary: dict[str, object],
) -> str:
    return render_inventory_markdown(title, sections, owner_summary)

from __future__ import annotations

from collections import defaultdict
from collections.abc import Iterable, Sequence

from report_app.models import OwnerTotal, QueueSummary, Section


def summarize_sections(
    sections: Iterable[Section],
    *,
    known_owners: Sequence[str] | None = None,
    include_known_owners: bool = False,
) -> QueueSummary:
    copied_sections = [Section(item.owner, item.label, item.count) for item in sections]
    owner_counts: dict[str, int] = defaultdict(int)

    for section in copied_sections:
        owner_counts[section.owner] += section.count

    if include_known_owners:
        for owner in known_owners or ():
            owner_counts.setdefault(owner, 0)

    owner_totals = tuple(
        OwnerTotal(owner=owner, count=count)
        for owner, count in sorted(
            owner_counts.items(),
            key=lambda item: (-item[1], item[0].lower()),
        )
    )
    top_owner = owner_totals[0] if owner_totals else None

    return QueueSummary(
        section_count=len(copied_sections),
        total_items=sum(section.count for section in copied_sections),
        top_owner=top_owner,
        owner_totals=owner_totals,
    )

from __future__ import annotations

from dataclasses import dataclass


@dataclass(frozen=True)
class Section:
    owner: str
    label: str
    count: int

    @classmethod
    def from_mapping(cls, payload: dict[str, object]) -> "Section":
        return cls(
            owner=str(payload["owner"]),
            label=str(payload["label"]),
            count=int(payload["count"]),
        )

    def as_dict(self) -> dict[str, object]:
        return {
            "owner": self.owner,
            "label": self.label,
            "count": self.count,
        }


@dataclass(frozen=True)
class OwnerTotal:
    owner: str
    count: int

    def as_dict(self) -> dict[str, object]:
        return {"owner": self.owner, "count": self.count}


@dataclass(frozen=True)
class QueueSummary:
    section_count: int
    total_items: int
    top_owner: OwnerTotal | None
    owner_totals: tuple[OwnerTotal, ...]

    def as_dict(self) -> dict[str, object]:
        payload: dict[str, object] = {
            "section_count": self.section_count,
            "total_items": self.total_items,
            "owner_totals": [entry.as_dict() for entry in self.owner_totals],
        }
        payload["top_owner"] = None if self.top_owner is None else self.top_owner.as_dict()
        return payload

